SELECT survey_id, COUNT(observation_id) AS total_observations
FROM observed_species
GROUP BY survey_id;

SELECT surveyor_name
FROM surveyors
WHERE surveyor_id IN (SELECT surveyor_id FROM surveys);

SELECT DISTINCT species_name 
FROM species 
ORDER BY species_name ASC;

SELECT species_id, density, frequency, health_status
FROM observed_species
WHERE health_status = 'Healthy';
